#include <bits/stdc++.h>
#define int long long
using namespace std;
int shu;
int zs[40000], gs = 0, bj, a, b;
bool vis[40000] = {0};
int jl = 0;
int scf (int a) {
    int zuo = sqrt (sqrt (a)), you = min ((int)1000000, (int)sqrt (a)), mid;
    while (zuo != you) {
        mid = (zuo + you + 1) / 2;
        if (mid * mid * mid <= a) {
            zuo = mid;
        } else {
            you = mid - 1;
        }
    }
    return zuo;
}
signed main () {
    ios::sync_with_stdio (0);
    cin.tie (0), cout.tie (0);
    for(int i = 2; i <= 32000; i++) {
        if (!vis[i]) {
            zs[++gs] = i;
        }
        for (int j = 1; j <= gs && zs[j] * i <= 32000; j++) {
            vis[zs[j] * i] = true;
            if (i % zs[j] == 0) {
                break;
            }
        }
    }
    int lr;
    cin >> lr;
    while (lr--) {
        cin >> shu;
        bj = sqrt (sqrt (shu));
        a = 1;
        for (int i = 1; i <= gs && zs[i] <= bj; i++) {
            b = 0;
            while (shu % zs[i] == 0) {
                shu /= zs[i];
                b++;
                if (b % 3 == 0) {
                    a *= zs[i];
                }
            }
        }
        b = scf (shu);
        if (b * b * b == shu) {
            a *= b;
        }
        cout << a << '\n';
    }
    return 0;
}
